import React from 'react';
import { View, Text, type ViewStyle } from 'react-native';
import { KangurMobileCard as Card } from '../shared/KangurMobileUi';
import { ActionButton, LinkButton } from '../duels/duels-primitives/BaseComponents';
import { formatPracticeResultLabel, formatPracticeSummaryMeta } from './practice-utils';
import { PracticeSyncProofPanel } from './PracticeSyncProofPanel';
import { PracticeDuelsPanel } from './PracticeDuelsPanel';
import { PracticeLessonMasteryPanel } from './PracticeLessonMasteryPanel';
import { PracticeBadgesPanel } from './PracticeBadgesPanel';
import { PracticeResultsPanel } from './PracticeResultsPanel';
import { PracticeAssignmentsPanel } from './PracticeAssignmentsPanel';
import { PracticeLessonCheckpointsPanel } from './PracticeLessonCheckpointsPanel';
import { translateKangurMobileActionLabel } from '../shared/translateKangurMobileActionLabel';
import { createKangurPlanHref } from '../lessons/lessonHref';
import { getLocalizedKangurMetadataBadgeName } from '@kangur/core';
export { type PracticeCompletionCardProps } from './completion-card-types';

function CompletionHeader(props: {
  copy: PracticeCompletionCardProps['copy'];
  correctAnswers: number;
  questionsLength: number;
  completion: PracticeCompletionCardProps['completion'];
  locale: PracticeCompletionCardProps['locale'];
}): React.JSX.Element {
  return (
    <>
      <Text style={{ color: '#64748b', fontSize: 12, fontWeight: '700' }}>
        {props.copy({ de: 'Zusammenfassung', en: 'Summary', pl: 'Podsumowanie' })}
      </Text>
      <Text style={{ color: '#0f172a', fontSize: 24, fontWeight: '800' }}>
        {formatPracticeResultLabel(props.correctAnswers, props.questionsLength, props.locale)}
      </Text>
      <Text style={{ color: '#475569', fontSize: 14, lineHeight: 20 }}>
        {formatPracticeSummaryMeta(props.completion, props.locale)}
      </Text>
    </>
  );
}

function SyncPanel(props: {
  scoreSyncState: PracticeCompletionCardProps['scoreSyncState'];
  scoreSyncAppearance: PracticeCompletionCardProps['scoreSyncAppearance'];
  shouldShowSyncProof: boolean;
  copy: PracticeCompletionCardProps['copy'];
  locale: PracticeCompletionCardProps['locale'];
  practiceSyncProof: PracticeCompletionCardProps['practiceSyncProof'];
}): React.JSX.Element {
  return (
    <>
      {props.scoreSyncState !== null && props.scoreSyncAppearance !== null && (
        <View style={[props.scoreSyncAppearance as ViewStyle, { borderRadius: 18, borderWidth: 1, padding: 12 }]}>
          <Text style={{ color: '#0f172a', fontSize: 13, lineHeight: 18, fontWeight: '600' }}>
            {props.scoreSyncState.message}
          </Text>
        </View>
      )}
      {props.shouldShowSyncProof && (
        <PracticeSyncProofPanel copy={props.copy} locale={props.locale} practiceSyncProof={props.practiceSyncProof} />
      )}
    </>
  );
}

function NewBadgesPanel(props: {
  completion: PracticeCompletionCardProps['completion'];
  copy: PracticeCompletionCardProps['copy'];
  locale: PracticeCompletionCardProps['locale'];
}): React.JSX.Element {
  return (
    <View style={{ flexDirection: 'row', flexWrap: 'wrap', gap: 8 }}>
      {props.completion.newBadges.map((badgeId: string) => (
        <View key={badgeId} style={{ borderRadius: 999, borderWidth: 1, borderColor: '#c7d2fe', backgroundColor: '#eef2ff', paddingHorizontal: 12, paddingVertical: 7 }}>
          <Text style={{ color: '#4338ca', fontSize: 12, fontWeight: '700' }}>
            {props.copy({ de: 'Neues Abzeichen', en: 'New badge', pl: 'Nowa odznaka' })}: {getLocalizedKangurMetadataBadgeName(badgeId, props.locale, badgeId)}
          </Text>
        </View>
      ))}
    </View>
  );
}

function CompletionActions(props: {
  locale: PracticeCompletionCardProps['locale'];
  restart: PracticeCompletionCardProps['restart'];
  practiceModeHistoryHref: PracticeCompletionCardProps['practiceModeHistoryHref'];
  completionLessonAction: PracticeCompletionCardProps['completionLessonAction'];
  profileHref: PracticeCompletionCardProps['profileHref'];
}): React.JSX.Element {
  return (
    <View style={{ flexDirection: 'row', flexWrap: 'wrap', gap: 10 }}>
      <ActionButton label={translateKangurMobileActionLabel('Train again', props.locale)} onPress={props.restart} tone='primary' />
      <LinkButton href={props.practiceModeHistoryHref} label={translateKangurMobileActionLabel('View mode history', props.locale)} tone='secondary' />
      {props.completionLessonAction}
      <LinkButton href={createKangurPlanHref()} label={translateKangurMobileActionLabel('Open daily plan', props.locale)} tone='secondary' />
      <LinkButton href={props.profileHref} label={translateKangurMobileActionLabel('Back to profile', props.locale)} tone='brand' />
    </View>
  );
}

export function PracticeCompletionCard(props: PracticeCompletionCardProps): React.JSX.Element {
  return (
    <Card>
      <CompletionHeader
        copy={props.copy}
        correctAnswers={props.correctAnswers}
        questionsLength={props.questionsLength}
        completion={props.completion}
        locale={props.locale}
      />
      <SyncPanel
        scoreSyncState={props.scoreSyncState}
        scoreSyncAppearance={props.scoreSyncAppearance}
        shouldShowSyncProof={props.shouldShowSyncProof}
        copy={props.copy}
        locale={props.locale}
        practiceSyncProof={props.practiceSyncProof}
      />
      <NewBadgesPanel
        completion={props.completion}
        copy={props.copy}
        locale={props.locale}
      />
      <PracticeDuelsPanel
        practiceDuels={props.practiceDuels}
        openDuelSession={props.openDuelSession}
        copy={props.copy}
        locale={props.locale}
      />
      <PracticeLessonMasteryPanel
        lessonMastery={props.lessonMastery}
        lessonFocusSummary={props.lessonFocusSummary}
        strongestLesson={props.strongestLesson}
        weakestLesson={props.weakestLesson}
        copy={props.copy}
        locale={props.locale}
      />
      <PracticeBadgesPanel
        practiceBadges={props.practiceBadges}
        copy={props.copy}
        locale={props.locale}
      />
      <PracticeResultsPanel
        practiceRecentResults={props.practiceRecentResults}
        resultsHistoryHref={props.resultsHistoryHref}
        copy={props.copy}
        locale={props.locale}
      />
      <PracticeAssignmentsPanel
        practiceAssignments={props.practiceAssignments}
        copy={props.copy}
        locale={props.locale}
      />
      <PracticeLessonCheckpointsPanel
        lessonCheckpoints={props.lessonCheckpoints}
        copy={props.copy}
        locale={props.locale}
      />
      <CompletionActions
        locale={props.locale}
        restart={props.restart}
        practiceModeHistoryHref={props.practiceModeHistoryHref}
        completionLessonAction={props.completionLessonAction}
        profileHref={props.profileHref}
      />
    </Card>
  );
}

import React from 'react';
import { Text, View } from 'react-native';

import type { KangurMobileLocale } from '../i18n/kangurMobileI18n';
import { createKangurPlanHref } from '../lessons/lessonHref';
import {
  KangurMobileCard as Card,
  KangurMobileLinkButton as LinkButton,
  KangurMobilePill as Pill,
  type KangurMobileTone as Tone,
} from '../shared/KangurMobileUi';
import { translateKangurMobileActionLabel } from '../shared/translateKangurMobileActionLabel';
import {
  PRACTICE_COUNT_TONE,
  PRACTICE_KIND_TONE,
  formatPracticeQuestionCountLabel,
} from './practice-utils';

type PracticeCopy = (value: Record<string, string>) => string;

export interface PracticePreparationCardProps {
  copy: PracticeCopy;
  locale: KangurMobileLocale;
  practiceKindChipLabel: string;
  practiceModeHistoryHref: string;
  practiceSyncPreview: { body: string; label: string; tone: Tone };
  preparationLessonAction: React.ReactNode;
  questionsLength: number;
}

export function PracticePreparationCard({
  copy, locale, practiceKindChipLabel, practiceModeHistoryHref, practiceSyncPreview, preparationLessonAction, questionsLength,
}: PracticePreparationCardProps): React.JSX.Element {
  const renderInfo = (): React.JSX.Element => (
    <>
      <Text style={{ color: '#0f172a', fontSize: 22, fontWeight: '800' }}>{copy({ de: 'Trainingsplan', en: 'Session plan', pl: 'Plan sesji' })}</Text>
      <Text style={{ color: '#475569', fontSize: 14, lineHeight: 20 }}>
        {copy({
          de: 'Zum Start siehst du hier den Umfang der Serie, den Speicherweg und die schnellsten Wege zurück zu Lektionen, Verlauf und Tagesplan.',
          en: 'At the start, this shows the run size, the save path, and the quickest routes back to lessons, history, and the daily plan.',
          pl: 'Na starcie widzisz tutaj rozmiar serii, sposób zapisu oraz najszybsze przejścia do lekcji, historii i planu dnia.',
        })}
      </Text>
    </>
  );

  return (
    <Card>
      <Text style={{ color: '#64748b', fontSize: 12, fontWeight: '700' }}>{copy({ de: 'Vor dem Start', en: 'Before you start', pl: 'Przed startem' })}</Text>
      {renderInfo()}
      <View style={{ flexDirection: 'row', flexWrap: 'wrap', gap: 8 }}>
        <Pill label={formatPracticeQuestionCountLabel(questionsLength, locale)} tone={PRACTICE_COUNT_TONE} />
        <Pill label={practiceKindChipLabel} tone={PRACTICE_KIND_TONE} />
        <Pill label={practiceSyncPreview.label} tone={practiceSyncPreview.tone} />
      </View>
      <Text style={{ color: '#475569', fontSize: 13, lineHeight: 18 }}>{practiceSyncPreview.body}</Text>
      <View style={{ gap: 10 }}>
        {preparationLessonAction}
        <LinkButton borderRadius={16} centered href={practiceModeHistoryHref} label={translateKangurMobileActionLabel('View mode history', locale)} stretch tone='secondary' verticalPadding={12} />
        <LinkButton borderRadius={16} centered href={createKangurPlanHref()} label={translateKangurMobileActionLabel('Open daily plan', locale)} stretch tone='secondary' verticalPadding={12} />
      </View>
    </Card>
  );
}

import { View, Text, Pressable } from 'react-native';
import { type KangurMobileLocale } from '../i18n/kangurMobileI18n';
import { translateKangurMobileActionLabel } from '../shared/translateKangurMobileActionLabel';
import type { useKangurPracticeSyncProof } from './useKangurPracticeSyncProof';

type PracticeCopy = (value: Record<string, string>) => string;
type PracticeSyncProofState = ReturnType<typeof useKangurPracticeSyncProof>;

export function PracticeSyncProofPanel({
  copy,
  locale,
  practiceSyncProof,
}: {
  copy: PracticeCopy;
  locale: KangurMobileLocale;
  practiceSyncProof: PracticeSyncProofState;
}): React.JSX.Element {
  return (
    <View style={{ borderRadius: 18, borderWidth: 1, borderColor: '#dbeafe', backgroundColor: '#eff6ff', padding: 12, gap: 10 }}>
      <Text style={{ color: '#1d4ed8', fontSize: 12, fontWeight: '800' }}>
        {copy({ de: 'Entwickler-Prüfung der Synchronisierung', en: 'Developer sync checks', pl: 'Deweloperskie sprawdzenie synchronizacji' })}
      </Text>
      <Text style={{ color: '#1e3a8a', fontSize: 13, lineHeight: 18 }}>
        {copy({ de: 'Das prüft dieselben Daten für Ergebnisse, Profil, Tagesplan und Rangliste.', en: 'Checks same sync data.', pl: 'Sprawdza dane synchronizacji.' })}
      </Text>
      {practiceSyncProof.isLoading ? (
        <Text style={{ color: '#1e3a8a', fontSize: 13 }}>{copy({ de: 'Laden...', en: 'Loading...', pl: 'Ładowanie...' })}</Text>
      ) : (
        <View style={{ gap: 8 }}>
          {practiceSyncProof.snapshot.surfaces.map((surface) => (
            <View key={surface.label} style={{ borderRadius: 14, borderWidth: 1, borderColor: surface.status === 'ready' ? '#86efac' : '#fca5a5', backgroundColor: surface.status === 'ready' ? '#f0fdf4' : '#fef2f2', padding: 10, gap: 4 }}>
              <Text style={{ color: surface.status === 'ready' ? '#166534' : '#b91c1c', fontSize: 13, fontWeight: '800' }}>
                {surface.label}: {surface.status === 'ready' ? copy({ de: 'bereit', en: 'ready', pl: 'gotowe' }) : copy({ de: 'fehlt', en: 'missing', pl: 'brak' })}
              </Text>
              <Text style={{ color: surface.status === 'ready' ? '#166534' : '#991b1b', fontSize: 13 }}>{surface.detail}</Text>
            </View>
          ))}
        </View>
      )}
      {practiceSyncProof.error !== null ? <Text style={{ color: '#991b1b', fontSize: 13 }}>{practiceSyncProof.error}</Text> : null}
      <Pressable onPress={() => { void practiceSyncProof.refresh(); }} style={{ alignSelf: 'flex-start', borderRadius: 999, borderWidth: 1, borderColor: '#93c5fd', backgroundColor: '#ffffff', paddingHorizontal: 12, paddingVertical: 9 }}>
        <Text style={{ color: '#1d4ed8', fontWeight: '700' }}>{translateKangurMobileActionLabel('Refresh proof', locale)}</Text>
      </Pressable>
    </View>
  );
}

import type { KangurPracticeOperation } from '@kangur/core';
import type { KangurProgressState, KangurScore } from '@kangur/contracts/kangur';

type PracticeSyncScoreMatchInput = {
  expectedCorrectAnswers: number;
  expectedTotalQuestions: number;
  operation: KangurPracticeOperation;
  runStartedAt: number;
  scores: KangurScore[];
};

export const findExactPracticeSyncScoreMatches = ({
  expectedCorrectAnswers,
  expectedTotalQuestions,
  operation,
  scores,
}: Omit<PracticeSyncScoreMatchInput, 'runStartedAt'>): KangurScore[] =>
  scores.filter(
    (score) =>
      score.operation === operation &&
      score.correct_answers === expectedCorrectAnswers &&
      score.total_questions === expectedTotalQuestions,
  );

export const canUseRunStartedAt = (runStartedAt: number): boolean =>
  Number.isFinite(runStartedAt) && runStartedAt > 0;

export const wasScoreCreatedAfterRunStart = (
  score: KangurScore,
  runStartedAt: number,
): boolean => {
  const createdAt = Date.parse(score.created_date);
  return Number.isFinite(createdAt) && createdAt >= runStartedAt;
};

export const findExactPracticeSyncScoreMatchCreatedAfterRunStart = (
  scores: KangurScore[],
  runStartedAt: number,
): KangurScore | null =>
  scores.find((score) => wasScoreCreatedAfterRunStart(score, runStartedAt)) ?? null;

export const findMatchingKangurPracticeSyncScore = ({
  expectedCorrectAnswers,
  expectedTotalQuestions,
  operation,
  runStartedAt,
  scores,
}: PracticeSyncScoreMatchInput): KangurScore | null => {
  const exactMatches = findExactPracticeSyncScoreMatches({
    expectedCorrectAnswers,
    expectedTotalQuestions,
    operation,
    scores,
  });

  if (exactMatches.length === 0) {
    return null;
  }

  if (!canUseRunStartedAt(runStartedAt)) {
    return exactMatches[0] ?? null;
  }

  return findExactPracticeSyncScoreMatchCreatedAfterRunStart(exactMatches, runStartedAt);
};

